#include <stdio.h>
#include <stdbool.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int a[3005]; long long sum=0;
        for(int i=0;i<N;i++){ scanf("%d",&a[i]); sum+=a[i]; }
        if(sum % N != 0){
            printf("-1\n");
            continue;
        }
        int steps=0;
        while(true){
            int maxIdx=0, minIdx=0;
            for(int i=1;i<N;i++){
                if(a[i]>a[maxIdx]) maxIdx=i;
                if(a[i]<a[minIdx]) minIdx=i;
            }
            if(a[maxIdx]==a[minIdx]) break; // all equal
            int P=a[maxIdx], Q=a[minIdx];
            int R = (P - Q + 1) / 2; // ceil((P-Q)/2)
            a[maxIdx] = P - R;
            a[minIdx] = Q + R;
            steps++;
        }
        printf("%d\n",steps);
    }
    return 0;
}

