#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> a(N);
        long long sum=0;
        for(int &x:a){cin>>x; sum+=x;}
        if(sum%N){ cout<<-1<<"\n"; continue; }
        int steps=0;
        multiset<int> ms(a.begin(), a.end());
        while(true){
            int mn=*ms.begin();
            int mx=*ms.rbegin();
            if(mn==mx) break;
            ms.erase(ms.find(mx));
            ms.erase(ms.find(mn));
            int R = (mx - mn + 1)/2; // ceil
            int newMx = mx - R;
            int newMn = mn + R;
            ms.insert(newMx);
            ms.insert(newMn);
            steps++;
        }
        cout<<steps<<"\n";
    }
    return 0;
}

