import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            int[] a = new int[N];
            long sum = 0;
            for (int i = 0; i < N; i++) { a[i] = Integer.parseInt(st.nextToken()); sum += a[i]; }
            if (sum % N != 0) { out.append(-1).append('\n'); continue; }
            TreeMap<Integer,Integer> map = new TreeMap<>();
            for (int v : a) map.merge(v,1,Integer::sum);
            int steps = 0;
            while (true) {
                int mn = map.firstKey();
                int mx = map.lastKey();
                if (mn == mx) break;
                // remove one occurrence of mx and mn
                dec(map,mx);
                dec(map,mn);
                int R = (mx - mn + 1) / 2; // ceil
                int newMx = mx - R;
                int newMn = mn + R;
                map.merge(newMx,1,Integer::sum);
                map.merge(newMn,1,Integer::sum);
                steps++;
            }
            out.append(steps).append('\n');
        }
        System.out.print(out.toString());
    }
    private static void dec(TreeMap<Integer,Integer> map, int key){
        int cnt = map.get(key);
        if (cnt == 1) map.remove(key);
        else map.put(key,cnt-1);
    }
}

