const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  let a = new Array(N);
  let sum = 0;
  for (let i = 0; i < N; i++) { a[i] = Number(input[idx++]); sum += a[i]; }
  if (sum % N !== 0) { outputs.push('-1'); continue; }
  let steps = 0;
  while (true) {
    let mn = Math.min(...a);
    let mx = Math.max(...a);
    if (mn === mx) break;
    const R = Math.floor((mx - mn + 1) / 2); // ceil
    const imx = a.indexOf(mx);
    const imn = a.indexOf(mn);
    a[imx] = mx - R;
    a[imn] = mn + R;
    steps++;
  }
  outputs.push(String(steps));
}
